code = """import json
import pandas as pd

# Load data
children_books = locals()['var_functions.query_db:34']
reviews_path = locals()['var_functions.query_db:24']

with open(reviews_path, 'r') as f:
    reviews_2020 = json.load(f)

# Create DataFrames
df_books = pd.DataFrame(children_books)
df_reviews = pd.DataFrame(reviews_2020)

# Extract numeric IDs for matching (both are strings)
df_books['id_num'] = df_books['book_id'].str.replace('bookid_', '')
df_reviews['id_num'] = df_reviews['purchase_id'].str.replace('purchaseid_', '')

# Merge on the numeric ID
merged = pd.merge(df_books, df_reviews, on='id_num', how='inner')

# Convert rating to numeric
merged['rating'] = pd.to_numeric(merged['rating'])

# Group by book and calculate average rating
grouped = merged.groupby(['book_id', 'title'])['rating'].mean().reset_index()

# Filter for books with average rating >= 4.5
filtered = grouped[grouped['rating'] >= 4.5].sort_values('rating', ascending=False)

# Create final result
result = filtered[['title', 'rating']].copy()
result['rating'] = result['rating'].round(2)

# Output
titles = result['title'].tolist()
ratings = result['rating'].tolist()
output = json.dumps({'titles': titles, 'ratings': ratings})
print('__RESULT__:')
print(output)"""

